from typing import Setfrom abc import abstractmethodfrom logic.calc_coverage.covpy_ebye_aggr._private.i_covpy_ebyeaggr import ICoveragePyEbyeAggregatorfrom logic.utils.path_validator import PathValidatorclass _ABaseCoverageEbyeAggregator(ICoveragePyEbyeAggregator):	"""		Rappresenta un `ICoveragePyEbyeAggregator` di base, ovvero che contiene la logica di controllo		comune ad ogni `ICoveragePyEbyeAggregator`.				Il formato del report di "coverage.py" trattato è specificato dai discendenti di questa classe astratta	"""		def __init__(self):		"""			Costruisce un nuovo _ABaseCoverageEbyeAggregator		"""		self._path_val: PathValidator = PathValidator()		self._excls: Set[str] = set()					def add_exclusion(self, excl_entity: str, pass_onerror: bool = False):		if (excl_entity is None) or (excl_entity == ""):			raise ValueError()		if excl_entity in self._excls:			self._excls.remove(excl_entity)		else:			if not pass_onerror:				raise ValueError()							def rem_exclusion(self, excl_entity: str, pass_onerror: bool = False):		if (excl_entity is None) or (excl_entity == ""):			raise ValueError()		if excl_entity not in self._excls:			self._excls.add(excl_entity)		else:			if not pass_onerror:				raise ValueError()							def aggregate(			self,			report_path: str,			focal_root: str,			aggr_path: str	):		self._assert_paths(report_path, focal_root, aggr_path)		self._ap__assert_report_type(report_path)		self._ap__aggregate_spec(report_path, focal_root, aggr_path, self._excls)					##	============================================================	##						PRIVATE METHODS	##	============================================================			@abstractmethod	def _ap__assert_report_type(self, report_path: str):		"""			Verifica se il tipo di report, alla path fornita, corrisponde alla			tipologia di report di coverage trattata dai discendenti di questa			classe astratta.						Se la verifica va a buon fine quest' operazione è equivalente ad una no-op.			E' garantito all' interno di questo metodo:							- Che ogni `report_path` non abbia valore `None` nè sia una stringa vuota				- Che ogni `report_path` sia una path esistente e accessibile							Parameters			----------				report_path: str					Una stringa rappresentante la path che contiene il report di					coverage.py di cui verificare la tipologia								Raises			------				WrongReportTypeError					Si verifica se `report_path` rappresenta un report di una tipologia					non trattata dai discendenti di questa classe astratta		"""		pass			@abstractmethod	def _ap__aggregate_spec(			self,			report_path: str,			focal_root: str,			aggr_path: str,			exclusions: Set[str]	):		"""			Aggrega i dati di statement coverage memorizzati nel report alla path data,			trasformandoli in dati di entity-level statement coverage in base alle entità autonome			di codice (funzioni o metodi) definite nei module-files all' interno della			Focal Project Root Path fornita.			Vengono tralasciate eventuali entità autonome selezionate per l' esclusione			precedentemente alla chiamata di questa operazione.						Al termine dell' aggregazione i dati vengono scritti, nel formato descritto			dal contratto d' interfaccia, all' interno del file alla path `aggr_path`.			E' garantito all' interno di questo metodo:							- Che ogni parametro non abbia valore `None` nè sia una stringa vuota				- Che ogni parametro sia una path esistente e accessibile							Parameters			----------				report_path: str					Una stringa rappresentante la path che contiene il report di coverage.py					da utilizzare				focal_root: str					Una stringa rappresentante la Focal Project Root Path legata al report					fornito in cui si trovano le funzioni in base a cui aggregare i dati				aggr_path: str					Una stringa rappresentante la path che conterrà i dati aggregati nel formato					descritto nel contratto d' interfaccia				exclusions: Set[str]					Un insieme di stringhe rappresentante le entità autonome da escludere					nell' aggregazione dei dati		"""		pass			##	============================================================	##						PRIVATE METHODS	##	============================================================			def _assert_paths(			self,			report_path: str,			focal_root: str,			aggr_path: str	):		"""			Verifica se le paths fornite siano valide per essere utilizzate			nell' operazione `.aggregate(...)`.			Se la verifica va a buon fine quest' operazione è equivalente ad una no-op			Parameters			----------				report_path: str					Una stringa rappresentante la path che contiene il report di coverage.py					da utilizzare				focal_root: str					Una stringa rappresentante la Focal Project Root Path legata al report					fornito in cui si trovano le funzioni in base a cui aggregare i dati				aggr_path: str					Una stringa rappresentante la path che conterrà i dati aggregati nel formato					descritto nel contratto d' interfaccia			Raises			------				ValueError					Si verifica se:						- Il parametro `report_path` ha valore `None` oppure è una stringa vuota						- Il parametro `focal_root` ha valore `None` oppure è una stringa vuota						- Il parametro `aggr_path` ha valore `None` oppure è una stringa vuota						- Il parametro `focal_root` rappresenta una path inesistente o inaccessibile						- Il parametro `aggr_path` rappresenta una path inesistente o inaccessibile		"""		if (			(report_path is None) or (report_path == "") or			(focal_root is None) or (focal_root == "") or			(aggr_path is None) or (aggr_path == "")		):			raise ValueError()				try:			self._path_val.assert_path(report_path)			self._path_val.assert_path(focal_root)			self._path_val.assert_path(aggr_path)		except (			NotADirectoryError, FileNotFoundError,			PermissionError, OSError		):			raise ValueError()